// MARK: - Promo Service

class PromoService {
    
    static let shared = PromoService()
    
    private let appliedPromosKey = "appliedPromoCodes"
    private let activePromoKey = "activePromoCode"
    private let activeDiscountKey = "activeDiscount"
    
    private init() {}
    
    // Validate and apply promo code
    func applyPromoCode(code: String, discount: Int, completion: @escaping (PromoApplicationResult) -> Void) {
        // Validate inputs
        guard !code.isEmpty else {
            completion(PromoApplicationResult(success: false, message: "Invalid promo code.", appliedDiscount: nil, promoCode: nil))
            return
        }
        
        guard discount > 0 && discount <= 100 else {
            completion(PromoApplicationResult(success: false, message: "Invalid discount percentage. Must be between 1 and 100.", appliedDiscount: nil, promoCode: nil))
            return
        }
        
        // Check if promo code was already used
        if hasPromoCodeBeenUsed(code) {
            completion(PromoApplicationResult(success: false, message: "Promo code '\(code)' has already been applied to your account.", appliedDiscount: nil, promoCode: code))
            return
        }
        
        // Simulate server-side validation
        validatePromoCodeWithServer(code: code, discount: discount) { [weak self] isValid in
            guard let self = self else { return }
            
            if isValid {
                self.savePromoCode(code: code, discount: discount)
                completion(PromoApplicationResult(
                    success: true,
                    message: "Promo code '\(code)' applied successfully! You get \(discount)% off.",
                    appliedDiscount: discount,
                    promoCode: code
                ))
                
                NotificationCenter.default.post(
                    name: .promoCodeApplied,
                    object: nil,
                    userInfo: ["code": code, "discount": discount]
                )
            } else {
                completion(PromoApplicationResult(
                    success: false,
                    message: "Promo code '\(code)' is invalid or has expired.",
                    appliedDiscount: nil,
                    promoCode: code
                ))
            }
        }
    }
    
    private func validatePromoCodeWithServer(code: String, discount: Int, completion: @escaping (Bool) -> Void) {
        // In a real app, this would make a network request to validate the promo code
        // For demo purposes, we simulate a network call
        DispatchQueue.global().asyncAfter(deadline: .now() + 0.5) {
            // Simulate validation: reject codes that are too short or contain invalid characters
            let isValid = code.count >= 3 && code.rangeOfCharacter(from: .alphanumerics.inverted) == nil
            DispatchQueue.main.async {
                completion(isValid)
            }
        }
    }
    
    private func hasPromoCodeBeenUsed(_ code: String) -> Bool {
        let appliedCodes = UserDefaults.standard.stringArray(forKey: appliedPromosKey) ?? []
        return appliedCodes.contains(code.uppercased())
    }
    
    private func savePromoCode(code: String, discount: Int) {
        var appliedCodes = UserDefaults.standard.stringArray(forKey: appliedPromosKey) ?? []
        appliedCodes.append(code.uppercased())
        UserDefaults.standard.set(appliedCodes, forKey: appliedPromosKey)
        UserDefaults.standard.set(code.uppercased(), forKey: activePromoKey)
        UserDefaults.standard.set(discount, forKey: activeDiscountKey)
    }
    
    func getActivePromo() -> (code: String, discount: Int)? {
        guard let code = UserDefaults.standard.string(forKey: activePromoKey) else { return nil }
        let discount = UserDefaults.standard.integer(forKey: activeDiscountKey)
        guard discount > 0 else { return nil }
        return (code, discount)
    }
    
    func clearActivePromo() {
        UserDefaults.standard.removeObject(forKey: activePromoKey)
        UserDefaults.standard.removeObject(forKey: activeDiscountKey)
    }
    
    func getAllAppliedCodes() -> [String] {
        return UserDefaults.standard.stringArray(forKey: appliedPromosKey) ?? []
    }
}

