// MARK: - Universal Link Handler

class UniversalLinkHandler {
    
    static let shared = UniversalLinkHandler()
    
    private let validHost = "myapp.com"
    private let promoPath = "/promo"
    
    private init() {}
    
    struct PromoLinkParameters {
        let code: String
        let discount: Int
    }
    
    enum LinkHandlingResult {
        case promo(PromoLinkParameters)
        case unsupported(String)
        case invalid(String)
    }
    
    func handleUniversalLink(_ url: URL) -> LinkHandlingResult {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return .invalid("Could not parse URL.")
        }
        
        // Validate host
        guard components.host == validHost else {
            return .invalid("Unrecognized host: \(components.host ?? "unknown")")
        }
        
        // Route based on path
        switch components.path {
        case promoPath:
            return parsePromoLink(components: components)
        default:
            return .unsupported("Unsupported link path: \(components.path)")
        }
    }
    
    private func parsePromoLink(components: URLComponents) -> LinkHandlingResult {
        let queryItems = components.queryItems ?? []
        
        guard let codeItem = queryItems.first(where: { $0.name == "code" }),
              let code = codeItem.value,
              !code.isEmpty else {
            return .invalid("Missing or empty promo code parameter.")
        }
        
        guard let discountItem = queryItems.first(where: { $0.name == "discount" }),
              let discountString = discountItem.value,
              let discount = Int(discountString) else {
            return .invalid("Missing or invalid discount parameter.")
        }
        
        guard discount > 0 && discount <= 100 else {
            return .invalid("Discount must be between 1 and 100. Got: \(discount)")
        }
        
        let sanitizedCode = code.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        
        return .promo(PromoLinkParameters(code: sanitizedCode, discount: discount))
    }
}

