    private func processPromoCode(code: String, discount: Int) {
        activityIndicator.startAnimating()
        applyButton.isEnabled = false
        
        PromoAnalytics.shared.trackPromoLinkOpened(code: code, discount: discount, source: "universal_link")
        
        PromoService.shared.applyPromoCode(code: code, discount: discount) { [weak self] result in
            guard let self = self else { return }
            
            self.activityIndicator.stopAnimating()
            self.applyButton.isEnabled = true
            
            if result.success {
                PromoAnalytics.shared.trackPromoApplied(code: code, discount: discount)
                self.showSuccessBanner(code: code, discount: discount)
            } else {
                PromoAnalytics.shared.trackPromoFailed(code: code, reason: result.message)
                self.showErrorBanner(message: result.message)
            }
            
            self.updatePromoStatus()
        }
    }
    
