    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    @objc private func applyButtonTapped() {
        guard let code = manualEntryField.text?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased(),
              !code.isEmpty else {
            showAlert(title: "Error", message: "Please enter a promo code.")
            return
        }
        
        // For manual entry, prompt for discount or use a default
        let alert = UIAlertController(title: "Enter Discount", message: "Enter the discount percentage for code \(code):", preferredStyle: .alert)
        alert.addTextField { textField in
            textField.placeholder = "Discount % (e.g., 50)"
            textField.keyboardType = .numberPad
        }
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Apply", style: .default) { [weak self] _ in
            guard let discountText = alert.textFields?.first?.text,
                  let discount = Int(discountText) else {
                self?.showAlert(title: "Error", message: "Please enter a valid discount percentage.")
                return
            }
            self?.manualEntryField.text = ""
            self?.processPromoCode(code: code, discount: discount)
        })
        present(alert, animated: true)
    }
    
    @objc private func handlePromoApplied(_ notification: Notification) {
        updatePromoStatus()
    }
    
    deinit {
        NotificationCenter.default.removeObserver(self)
    }
}

// MARK: - Scene Delegate

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    private var promoViewController: PromoViewController?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = scene as? UIWindowScene else { return }
        
        let window = UIWindow(windowScene: windowScene)
        let promoVC = PromoViewController()
        self.promoViewController = promoVC
        let navController = UINavigationController(rootViewController: promoVC)
        navController.navigationBar.prefersLargeTitles = true
        window.rootViewController = navController
        window.makeKeyAndVisible()
        self.window = window
        
        // Handle universal links from cold launch
        if let urlContext = connectionOptions.urlContexts.first {
            handleIncomingURL(urlContext.url)
        }
        
        if let userActivity = connectionOptions.userActivities.first,
           userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            handleIncomingURL(url)
        }
    }
    
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        handleIncomingURL(url)
    }
    
    func scene(_ scene: UIScene, openURLContexts URLContexts: Set<UIOpenURLContext>) {
        guard let url = URLContexts.first?.url else { return }
        handleIncomingURL(url)
    }
    
    private func handleIncomingURL(_ url: URL) {
        print("[UniversalLink] Received URL: \(url.absoluteString)")
        
        let result = UniversalLinkHandler.shared.handleUniversalLink(url)
        
        switch result {
        case .promo(let params):
            print("[UniversalLink] Promo link detected - Code: \(params.code), Discount: \(params.discount)%")
            promoViewController?.handlePromoFromLink(code: params.code, discount: params.discount)
            
        case .unsupported(let message):
            print("[UniversalLink] Unsupported link: \(message)")
            
        case .invalid(let message):
            print("[UniversalLink] Invalid link: \(message)")
        }
    }
}

// MARK: - App Delegate

@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        return true
    }
    
    func application(_ application: UIApplication, configurationForConnecting connectingSceneSession: UISceneSession, options: UIScene.ConnectionOptions) -> UISceneConfiguration {
        let config = UISceneConfiguration(name: "Default Configuration", sessionRole: connectingSceneSession.role)
        config.delegateClass = SceneDelegate.self
        return config
    }
    
    // Fallback for iOS 12 and earlier (if needed)
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        let result = UniversalLinkHandler.shared.handleUniversalLink(url)
        switch result {
        case .promo(let params):
            print("[AppDelegate] Promo from universal link - Code: \(params.code), Discount: \(params.discount)%")
            return true
        case .unsupported, .invalid:
            return false
        }
    }
}